(function($) {
 'use strict';
 $('.navbar-toggle').on('click', function() {
 $('.tasty-menu').toggleClass('active');
 });
 $('a[href^="#"]').on('click', function(e) {
 var target = $(this.getAttribute('href'));
 if (target.length) {
 e.preventDefault();
 $('html, body').stop().animate({
 scrollTop: target.offset().top - 100
 }, 500);
 }
 });
 $('#commentForm').on('submit', function(e) {
 e.preventDefault();
 
 var form = $(this);
 var submitBtn = form.find('button[type="submit"]');
 var originalText = submitBtn.html();
 
 submitBtn.prop('disabled', true).html('<i class="fa fa-spinner fa-spin"></i> ' + scriptlog_vars.processing || 'Submitting...');
 
 $.ajax({
 url: scriptlog_vars.site_url + '/api/v1/comments',
 method: 'POST',
 data: form.serialize(),
 success: function(response) {
 if (response.success) {
 alert(response.message || 'Comment submitted successfully!');
 form[0].reset();
 location.reload();
 } else {
 alert(response.message || 'Error submitting comment');
 }
 },
 error: function(xhr) {
 var msg = 'Error submitting comment';
 try {
 var resp = JSON.parse(xhr.responseText);
 msg = resp.message || msg;
 } catch(e) {}
 alert(msg);
 },
 complete: function() {
 submitBtn.prop('disabled', false).html(originalText);
 }
 });
 });
 $('.search-form').on('submit', function(e) {
 var input = $(this).find('input[name="q"]');
 if (input.val().trim().length < 2) {
 e.preventDefault();
 alert('Please enter at least 2 characters to search');
 }
 });
 if ('IntersectionObserver' in window) {
 var lazyImages = document.querySelectorAll('img[data-src]');
 var imageObserver = new IntersectionObserver(function(entries, observer) {
 entries.forEach(function(entry) {
 if (entry.isIntersecting) {
 var img = entry.target;
 img.src = img.dataset.src;
 img.removeAttribute('data-src');
 imageObserver.unobserve(img);
 }
 });
 });
 lazyImages.forEach(function(img) {
 imageObserver.observe(img);
 });
 }
 $('.add-to-cart').on('click', function(e) {
 e.preventDefault();
 var btn = $(this);
 btn.prop('disabled', true).html('<i class="fa fa-spinner fa-spin"></i>');
 setTimeout(function() {
 btn.html('<i class="fa fa-check"></i> Added!');
 setTimeout(function() {
 btn.prop('disabled', false).html(btn.data('original-text') || 'Add to Cart');
 }, 2000);
 }, 500);
 });
 $('.newsletter-form').on('submit', function(e) {
 e.preventDefault();
 var form = $(this);
 var email = form.find('input[name="email"]').val();
 
 $.ajax({
 url: scriptlog_vars.api_url + '/newsletter/subscribe',
 method: 'POST',
 data: { email: email },
 success: function(response) {
 alert('Thank you for subscribing!');
 form[0].reset();
 },
 error: function() {
 alert('Error subscribing. Please try again.');
 }
 });
 });
})(jQuery);